function criticalConnections(n, connections) {
    const graph = new Map();
    for (const [fr, to] of connections) {
        if (!graph.has(fr)) {
            graph.set(fr, []);
        }
        if (!graph.has(to)) {
            graph.set(to, []);
        }
        graph.get(fr).push(to);
        graph.get(to).push(fr);
    }

    const rank = new Array(n).fill(-1);
    const result = [];
    dfs(0, -1, 0, rank, graph, result);
    return result;
}

function dfs(node, parent, depth, rank, graph, result) {
    rank[node] = depth;
    for (const neighbor of graph.get(node)) {
        if (neighbor === parent) {
            continue;
        }
        if (rank[neighbor] === -1) {
            dfs(neighbor, node, depth + 1, rank, graph, result);
        }
        rank[node] = Math.min(rank[node], rank[neighbor]);
        if (rank[neighbor] === depth + 1) {
            result.push([node, neighbor]);
        }
    }
}
```


    The problem can be solved using a Depth-First Search (DFS) algorithm. The algorithm starts by creating a graph from the server connections, represented by an adjacency list. Then a Rank array is initialized with -1 as initial value, which will store the rank/depth of each node in the DFS traversal.

We execute a DFS starting from the initial node (0) and at each step, we update the rank of the current node accordingly. Then, we visit neighbors. If the neighbor is the parent node from where the current node is visited, we just skip and continue to the next neighbor.

If the neighbor node has not been visited yet, DFS is called recursively for the neighbor node, increasing the depth by one. After the DFS call, we update the current node's rank with the minimum rank between its rank and the neighbors' rank if a neighbor node has been visited earlier.

Finally, we check if the neighbor node's rank is equal to the depth of the current node plus one. If true, it means the connection between the current node and the neighbor node is critical, thus we add this connection to the result.

Once the algorithm is done executing the DFS, the result will contain all critical connections.

